// Parse sitemap XML and extract URLs
const xml = $input.first().json.data;
const urlMatches = xml.match(/<loc>(.*?)<\/loc>/g) || [];

const urls = urlMatches.map(match => {
  const url = match.replace(/<\/?loc>/g, '');
  const path = new URL(url).pathname;

  // Extract content type from URL pattern
  let content_type = 'page';
  if (path.includes('/blog/')) content_type = 'blog';
  else if (path.includes('/programs/')) content_type = 'program';
  else if (path.includes('/resources/')) content_type = 'resource';
  else if (path.includes('/news/')) content_type = 'news';

  return {
    url,
    path,
    content_type,
    discovered_at: new Date().toISOString()
  };
});

return urls.map(u => ({ json: u }));
